// src/views/VisitorProfile.js - صفحة الزائر لحساب المدير (6 مربعات - قراءة فقط)
import React, { useState, useEffect } from "react";
import Footer from "components/Footers/Footer.js";
import Navbar from "components/Navbars/AuthNavbar.js";
import SocialFooter from "components/Common/socialFooter";

export default function VisitorManagerProfile() {
  // ==================== DONNÉES DU PROFIL MANAGER ====================
  const [managerInfo, setManagerInfo] = useState({
    name: "Ahmed Benali",
    role: "Directeur du Restaurant",
    experience: "12 ans d'expérience",
    skills: ["Management", "Gestion d'équipe", "Planification", "Service client", "Gestion des stocks", "Marketing"],
    bio: "Passionné par la restauration depuis plus de 12 ans, je dirige ce magnifique établissement avec une équipe dévouée pour offrir la meilleure expérience culinaire à nos clients.",
    email: "ahmed.benali@andalus-restaurant.dz",
    phone: "+213 5 55 55 55 55",
    location: "Alger, Algérie",
    languages: ["Français", "Arabe", "Anglais"],
    coverImage: "https://images.unsplash.com/photo-1517248135467-4c7edcad34c4",
    profileImage: "https://randomuser.me/api/portraits/men/32.jpg"
  });
  
  // ==================== SOCIAL LINKS ====================
  const [socialLinks, setSocialLinks] = useState({
    facebook: "",
    instagram: "",
    twitter: "",
    linkedin: "",
    tiktok: ""
  });
  
  // ==================== DONNÉES DU RESTAURANT ====================
  const [restaurantData, setRestaurantData] = useState({
    id: 1,
    name: "Restaurant Andalous",
    location: "Alger, Algérie",
    description: "Les meilleurs plats arabes et internationaux dans une ambiance familiale",
    image: "https://images.unsplash.com/photo-1517248135467-4c7edcad34c4",
    logo: "https://cdn-icons-png.flaticon.com/512/1046/1046784.png",
    phone: "+213 5 55 55 55 55",
    email: "info@andalus-restaurant.dz",
    rating: 4.8,
    employees: 12
  });
  
  // ==================== DONNÉES DES TABLES ====================
  const [tables, setTables] = useState([]);
  
  // ==================== DONNÉES DES GROUPES ====================
  const [groups, setGroups] = useState([
    { id: 1, name: "Groupe 1", tableIds: [1,2,3,4,5,6,7,8,9], tableRange: { start: 1, end: 9 } }
  ]);
  
  // ==================== DONNÉES DES EMPLOYÉS ====================
  const [employees, setEmployees] = useState([
    { id: 1, name: "Youssef", role: "Employé", groupId: 1, status: "active" },
    { id: 2, name: "Mohamed", role: "Employé", groupId: null, status: "active" }
  ]);
  
  // ==================== DONNÉES DU MENU ====================
  const [menuCategories, setMenuCategories] = useState([
    { id: 1, name: "Chicha", icon: "💨", color: "#ff6b6b", products: [
      { id: 101, name: "Chicha Pomme", price: 15, image: "https://cdn-icons-png.flaticon.com/512/1998/1998626.png" },
      { id: 102, name: "Chicha Raisin", price: 15, image: "https://cdn-icons-png.flaticon.com/512/1998/1998626.png" },
      { id: 103, name: "Chicha Menthe", price: 15, image: "https://cdn-icons-png.flaticon.com/512/1998/1998626.png" }
    ] },
    { id: 2, name: "Plats", icon: "🍔", color: "#4ecdc4", products: [
      { id: 201, name: "Burger", price: 12, image: "https://cdn-icons-png.flaticon.com/512/1046/1046784.png" },
      { id: 202, name: "Pizza", price: 18, image: "https://cdn-icons-png.flaticon.com/512/1046/1046796.png" }
    ] },
    { id: 3, name: "Boissons", icon: "🥤", color: "#45b7d1", products: [
      { id: 301, name: "Coca Cola", price: 3, image: "https://cdn-icons-png.flaticon.com/512/1046/1046855.png" },
      { id: 302, name: "Jus d'Orange", price: 5, image: "https://cdn-icons-png.flaticon.com/512/1046/1046874.png" }
    ] },
    { id: 4, name: "Desserts", icon: "🍰", color: "#f9ca24", products: [
      { id: 401, name: "Gâteau", price: 7, image: "https://cdn-icons-png.flaticon.com/512/1046/1046790.png" },
      { id: 402, name: "Glace", price: 5, image: "https://cdn-icons-png.flaticon.com/512/1046/1046800.png" }
    ] }
  ]);
  
  // ==================== DONNÉES DES FACTURES ====================
  const [invoices, setInvoices] = useState([]);
  const [groupInvoices, setGroupInvoices] = useState([]);
  const [restaurantInvoice, setRestaurantInvoice] = useState(null);
  const [showInvoices, setShowInvoices] = useState(false);
  const [invoiceViewType, setInvoiceViewType] = useState("tables");
  
  // ==================== CHARGEMENT DES DONNÉES ====================
  useEffect(() => {
    const savedManagerInfo = localStorage.getItem("managerInfo");
    if (savedManagerInfo) setManagerInfo(JSON.parse(savedManagerInfo));
    
    const savedRestaurantData = localStorage.getItem("restaurantData");
    if (savedRestaurantData) setRestaurantData(JSON.parse(savedRestaurantData));
    
    const savedTables = localStorage.getItem("managerTables");
    if (savedTables) setTables(JSON.parse(savedTables));
    
    const savedGroups = localStorage.getItem("managerGroups");
    if (savedGroups) setGroups(JSON.parse(savedGroups));
    
    const savedEmployees = localStorage.getItem("managerEmployees");
    if (savedEmployees) setEmployees(JSON.parse(savedEmployees));
    
    const savedMenu = localStorage.getItem("managerMenu");
    if (savedMenu) setMenuCategories(JSON.parse(savedMenu));
    
    const savedSocialLinks = localStorage.getItem("managerSocialLinks");
    if (savedSocialLinks) setSocialLinks(JSON.parse(savedSocialLinks));
    
    // توليد فواتير تجريبية
    generateMockInvoices();
  }, []);
  
  const generateMockInvoices = () => {
    const mockInvoices = [];
    for (let i = 1; i <= 10; i++) {
      mockInvoices.push({
        id: i,
        tableNumber: i,
        groupId: i <= 5 ? 1 : 2,
        groupName: i <= 5 ? "Groupe 1" : "Groupe 2",
        total: Math.floor(Math.random() * 500 + 100),
        items: Math.floor(Math.random() * 5 + 1),
        date: new Date().toISOString().split('T')[0]
      });
    }
    setInvoices(mockInvoices);
    
    const groupTotals = {};
    mockInvoices.forEach(inv => {
      if (!groupTotals[inv.groupId]) {
        groupTotals[inv.groupId] = {
          groupId: inv.groupId,
          groupName: inv.groupName,
          total: 0,
          tableCount: 0,
          orderCount: 0
        };
      }
      groupTotals[inv.groupId].total += inv.total;
      groupTotals[inv.groupId].tableCount++;
      groupTotals[inv.groupId].orderCount += inv.items;
    });
    setGroupInvoices(Object.values(groupTotals));
    
    const restaurantTotal = mockInvoices.reduce((sum, inv) => sum + inv.total, 0);
    setRestaurantInvoice({
      total: restaurantTotal,
      tableCount: mockInvoices.length,
      orderCount: mockInvoices.reduce((sum, inv) => sum + inv.items, 0),
      date: new Date().toISOString().split('T')[0]
    });
  };
  
  const getTotalRevenue = () => {
    return invoices.reduce((sum, inv) => sum + inv.total, 0);
  };
  
  // ==================== STYLES ====================
  const style = `
    @keyframes gradientShift {
      0% { background-position: 0% 50%; }
      50% { background-position: 100% 50%; }
      100% { background-position: 0% 50%; }
    }
    
    @keyframes shoot {
      0% { transform: translateX(0) translateY(0) rotate(45deg); opacity: 0; }
      5% { opacity: 1; }
      95% { opacity: 1; }
      100% { transform: translateX(-300px) translateY(300px) rotate(45deg); opacity: 0; }
    }
    
    @keyframes twinkle {
      0%, 100% { opacity: 0.2; transform: scale(1); }
      50% { opacity: 1; transform: scale(1.2); }
    }
    
    @keyframes gradient-border {
      0% { background-position: 0% 0%; }
      50% { background-position: 400% 0%; }
      100% { background-position: 0% 0%; }
    }
    
    @keyframes borderPulse {
      0%, 100% { opacity: 0.6; filter: blur(8px); }
      50% { opacity: 1; filter: blur(12px); }
    }
    
    @keyframes rainbowLine {
      0% { background-position: 0% 50%; }
      100% { background-position: 200% 50%; }
    }
    
    @keyframes fadeIn {
      from { opacity: 0; transform: translateY(20px); }
      to { opacity: 1; transform: translateY(0); }
    }
    
    .profile-hero-section {
      position: relative;
      background: linear-gradient(135deg, #0a0a2a, #1a1a3a, #0d0d2b, #0f0c29, #1a1a4a);
      background-size: 400% 400%;
      animation: gradientShift 12s ease infinite;
      min-height: 100vh;
      padding-top: 80px;
    }
    
    .shooting-stars {
      position: absolute;
      top: 0;
      left: 0;
      width: 100%;
      height: 100%;
      pointer-events: none;
      z-index: 1;
      overflow: hidden;
    }
    
    .star {
      position: absolute;
      background: white;
      border-radius: 50%;
      opacity: 0.6;
      animation: twinkle 3s ease-in-out infinite;
    }
    
    .shooting-star {
      position: absolute;
      width: 2px;
      height: 2px;
      background: linear-gradient(135deg, rgba(255,255,255,1) 0%, rgba(255,255,255,0) 100%);
      border-radius: 50%;
      opacity: 0;
      animation: shoot 2s ease-out infinite;
    }
    
    .hero-image {
      position: absolute;
      top: 0;
      width: 100%;
      height: 100%;
      background-position: center 30%;
      background-size: cover;
      filter: brightness(0.85) contrast(1.05);
      transition: transform 0.5s ease;
    }
    
    .hero-image:hover {
      transform: scale(1.01);
    }
    
    .hero-overlay {
      position: absolute;
      top: 0;
      left: 0;
      width: 100%;
      height: 100%;
      background: linear-gradient(180deg, rgba(0,0,0,0.2) 0%, rgba(0,0,0,0.05) 30%, rgba(0,0,0,0) 50%, rgba(26,26,58,0.6) 100%);
    }
    
    .bg-white-card {
      background: rgba(255, 255, 255, 0.12);
      backdrop-filter: blur(16px);
      border-radius: 28px;
      border: 1px solid rgba(255, 255, 255, 0.25);
      box-shadow: 0 20px 40px rgba(0, 0, 0, 0.2);
    }
    
    .gradient-border-box {
      position: relative;
      width: 150px;
      height: 150px;
      display: flex;
      align-items: center;
      justify-content: center;
      border-radius: 50%;
      margin-top: -60px;
      margin-left: -20px;
    }
    
    .gradient-border-box::before {
      content: "";
      position: absolute;
      inset: -4px;
      z-index: -1;
      background: linear-gradient(45deg, #ff0000, #ff7300, #fffb00, #48ff00, #00ffd5, #002bff, #7a00ff, #ff00c8, #ff0000);
      background-size: 450%;
      border-radius: 50%;
      animation: gradient-border 20s linear infinite;
      filter: blur(5px);
    }
    
    .gradient-border-box .content {
      width: calc(100% - 4px);
      height: calc(100% - 4px);
      background-size: cover;
      background-position: center;
      border-radius: 50%;
      box-shadow: 0 0 30px rgba(0,0,0,0.3);
    }
    
    .profile-glow {
      position: absolute;
      top: 50%;
      left: 50%;
      transform: translate(-50%, -50%);
      width: 170px;
      height: 170px;
      background: radial-gradient(circle, rgba(34,197,94,0.3) 0%, rgba(34,197,94,0) 70%);
      border-radius: 50%;
      z-index: -1;
      animation: borderPulse 2s ease-in-out infinite;
    }
    
    .action-buttons {
      display: flex;
      justify-content: center;
      gap: 15px;
      margin-top: 20px;
      margin-bottom: 20px;
    }
    
    .btn-contact {
      background: linear-gradient(135deg, #22c55e, #15803d);
      border: none;
      padding: 10px 25px;
      border-radius: 30px;
      color: white;
      font-weight: bold;
      cursor: pointer;
      transition: all 0.3s;
      font-size: 14px;
    }
    
    .btn-contact:hover {
      transform: scale(1.05);
      box-shadow: 0 5px 20px rgba(34,197,94,0.4);
    }
    
    .btn-comment {
      background: linear-gradient(135deg, #ff6b6b, #f5576c);
      border: none;
      padding: 10px 25px;
      border-radius: 30px;
      color: white;
      font-weight: bold;
      cursor: pointer;
      transition: all 0.3s;
      font-size: 14px;
    }
    
    .btn-comment:hover {
      transform: scale(1.05);
      box-shadow: 0 5px 20px rgba(255,107,107,0.4);
    }
    
    .status-badge {
      display: inline-block;
      padding: 5px 12px;
      border-radius: 20px;
      font-size: 12px;
      font-weight: bold;
      margin-left: 10px;
      background: #22c55e;
      color: white;
    }
    
    .skill-tag {
      display: inline-block;
      padding: 4px 10px;
      background: rgba(34,197,94,0.2);
      border-radius: 15px;
      font-size: 11px;
      margin: 2px;
      color: #4ade80;
      border: 1px solid rgba(34,197,94,0.4);
      backdrop-filter: blur(5px);
    }
    
    .manager-cards-container {
      display: grid;
      grid-template-columns: repeat(2, 1fr);
      gap: 30px;
      max-width: 1400px;
      margin: 40px auto 0;
      padding: 0 20px 30px;
      position: relative;
      z-index: 5;
    }
    
    .manager-cards-container::after {
      content: '';
      position: absolute;
      bottom: -15px;
      left: 10%;
      width: 80%;
      height: 4px;
      background: linear-gradient(90deg, transparent, #ff0000, #ff7300, #fffb00, #48ff00, #00ffd5, #002bff, #7a00ff, #ff00c8, #ff0000, transparent);
      background-size: 200% 100%;
      border-radius: 4px;
      animation: rainbowLine 3s linear infinite;
    }
    
    .manager-card {
      background: rgba(255, 255, 255, 0.1);
      backdrop-filter: blur(15px);
      border-radius: 30px;
      padding: 25px;
      transition: all 0.3s ease;
      border: 1px solid rgba(34, 197, 94, 0.3);
      animation: fadeIn 0.5s ease-out;
    }
    
    .manager-card:hover {
      transform: translateY(-5px);
      box-shadow: 0 10px 40px rgba(0,0,0,0.3);
      border-color: rgba(34, 197, 94, 0.6);
    }
    
    .card-title {
      font-size: 1.5rem;
      font-weight: bold;
      color: white;
      margin-bottom: 20px;
      display: flex;
      align-items: center;
      gap: 10px;
      border-bottom: 2px solid #22c55e;
      padding-bottom: 10px;
    }
    
    .input-group {
      margin-bottom: 15px;
    }
    
    .input-group label {
      display: block;
      color: rgba(255,255,255,0.8);
      margin-bottom: 5px;
      font-size: 0.9rem;
    }
    
    .input-group input, .input-group select, .input-group textarea {
      width: 100%;
      padding: 10px;
      background: rgba(255,255,255,0.1);
      border: 1px solid rgba(34,197,94,0.3);
      border-radius: 15px;
      color: white;
      font-size: 0.9rem;
      transition: all 0.2s;
    }
    
    .table-list, .group-list, .employee-list {
      max-height: 300px;
      overflow-y: auto;
      margin-top: 15px;
    }
    
    .table-list::-webkit-scrollbar, .group-list::-webkit-scrollbar, .employee-list::-webkit-scrollbar {
      width: 6px;
    }
    
    .table-list::-webkit-scrollbar-track, .group-list::-webkit-scrollbar-track, .employee-list::-webkit-scrollbar-track {
      background: rgba(255,255,255,0.1);
      border-radius: 10px;
    }
    
    .table-list::-webkit-scrollbar-thumb, .group-list::-webkit-scrollbar-thumb, .employee-list::-webkit-scrollbar-thumb {
      background: #22c55e;
      border-radius: 10px;
    }
    
    .table-item, .group-item, .employee-item {
      background: rgba(255,255,255,0.08);
      padding: 10px;
      margin-bottom: 8px;
      border-radius: 15px;
      display: flex;
      justify-content: space-between;
      align-items: center;
    }
    
    .product-item {
      background: rgba(255,255,255,0.08);
      padding: 12px;
      margin-bottom: 8px;
      border-radius: 15px;
      display: flex;
      justify-content: space-between;
      align-items: center;
    }
    
    .invoice-stats {
      background: linear-gradient(135deg, #22c55e, #15803d);
      padding: 20px;
      border-radius: 20px;
      text-align: center;
      margin-bottom: 20px;
    }
    
    .invoice-stats h3 {
      color: white;
      font-size: 2rem;
      margin: 0;
    }
    
    .invoice-item {
      background: rgba(255,255,255,0.08);
      padding: 12px;
      margin-bottom: 8px;
      border-radius: 15px;
      display: flex;
      justify-content: space-between;
    }
    
    .group-invoice-item {
      background: rgba(59,130,246,0.2);
      border-left: 3px solid #3b82f6;
    }
    
    .restaurant-invoice {
      background: linear-gradient(135deg, rgba(34,197,94,0.2), rgba(34,197,94,0.05));
      border: 2px solid #22c55e;
    }
    
    .invoice-tabs {
      display: flex;
      gap: 10px;
      margin-bottom: 20px;
      flex-wrap: wrap;
    }
    
    .invoice-tab {
      background: rgba(255,255,255,0.1);
      border: 1px solid rgba(34,197,94,0.3);
      padding: 8px 16px;
      border-radius: 20px;
      color: white;
      cursor: pointer;
      transition: all 0.2s;
    }
    
    .invoice-tab.active {
      background: #22c55e;
      border-color: #22c55e;
    }
    
    .invoices-container {
      animation: fadeIn 0.3s ease-out;
    }
    
    .restaurant-card-preview {
      text-align: center;
    }
    
    .restaurant-card-preview img {
      width: 60px;
      height: 60px;
      border-radius: 50%;
      margin-bottom: 10px;
    }
    
    .btn-primary {
      background: linear-gradient(135deg, #22c55e, #15803d);
      border: none;
      padding: 10px 20px;
      border-radius: 25px;
      color: white;
      font-weight: bold;
      cursor: pointer;
      transition: all 0.2s;
      margin-top: 10px;
    }
    
    .btn-primary:hover {
      transform: scale(1.02);
      box-shadow: 0 5px 20px rgba(34,197,94,0.4);
    }
    
    @media (max-width: 768px) {
      .manager-cards-container {
        grid-template-columns: 1fr;
        gap: 20px;
        padding: 15px;
      }
      
      .manager-cards-container::after {
        width: 90%;
        left: 5%;
        bottom: -10px;
      }
      
      .gradient-border-box {
        width: 120px;
        height: 120px;
        margin-top: -50px;
        margin-left: 0;
      }
      
      .action-buttons {
        flex-direction: column;
        gap: 10px;
        align-items: center;
      }
      
      .card-title {
        font-size: 1.2rem;
      }
    }
  `;

  return (
    <>
      <style>{style}</style>
      <Navbar />
      
      <div className="profile-hero-section">
        <div className="shooting-stars">
          {[...Array(60)].map((_, i) => (
            <div key={i} className="star" style={{
              left: `${Math.random() * 100}%`,
              top: `${Math.random() * 100}%`,
              width: `${Math.random() * 3 + 1}px`,
              height: `${Math.random() * 3 + 1}px`,
              animationDelay: `${Math.random() * 5}s`,
              animationDuration: `${Math.random() * 3 + 2}s`
            }} />
          ))}
          {[...Array(10)].map((_, i) => (
            <div key={`shooting-${i}`} className="shooting-star" style={{
              left: `${Math.random() * 80 + 10}%`,
              top: `${Math.random() * 40}%`,
              width: `${Math.random() * 60 + 40}px`,
              height: '2px',
              animationDelay: `${Math.random() * 8}s`,
              animationDuration: `${Math.random() * 2 + 1.5}s`,
              transform: `rotate(${Math.random() * 60 + 30}deg)`,
              background: `linear-gradient(90deg, rgba(255,255,255,1) 0%, rgba(255,255,150,0.8) 30%, rgba(255,255,255,0) 100%)`
            }} />
          ))}
        </div>
        
        <main style={{ position: 'relative', zIndex: 10 }}>
          <section className="relative block" style={{ height: "350px", position: 'relative', overflow: 'hidden' }}>
            <div className="hero-image" style={{ 
              backgroundImage: `url(${managerInfo.coverImage})`,
              backgroundSize: 'cover',
              backgroundPosition: 'center 40%'
            }}></div>
            <div className="hero-overlay"></div>
          </section>
          
          <section className="relative py-16 bg-transparent">
            <div className="container mx-auto px-4">
              <div className="relative flex flex-col min-w-0 break-words bg-white-card w-full mb-6 shadow-xl rounded-lg -mt-48">
                <div className="px-6">
                  
                  <div className="flex flex-wrap justify-center">
                    <div className="w-full lg:w-3/12 px-4 lg:order-2 flex justify-center">
                      <div className="profile-image-wrapper" style={{ position: 'relative' }}>
                        <div className="profile-glow"></div>
                        <div className="gradient-border-box">
                          <img alt={managerInfo.name} src={managerInfo.profileImage} className="content" style={{ width: '100%', height: '100%', objectFit: 'cover', borderRadius: '50%' }} />
                        </div>
                      </div>
                    </div>
                  </div>
                  
                  <div className="text-center mt-12">
                    <h3 className="text-4xl font-semibold leading-normal mb-2 text-white">
                      {managerInfo.name}
                      <span className="status-badge">👑 Directeur</span>
                    </h3>
                    <div className="text-sm leading-normal mt-2 mb-2 text-gray-400 font-bold uppercase">
                      <i className="fas fa-map-marker-alt mr-2"></i> {managerInfo.location}
                    </div>
                    <div className="mb-2 text-gray-300 mt-10">
                      <i className="fas fa-briefcase mr-2 text-green-400"></i> {managerInfo.role}
                    </div>
                    <div className="mb-2 text-gray-300">
                      <i className="fas fa-calendar-alt mr-2 text-green-400"></i> {managerInfo.experience}
                    </div>
                  </div>
                  
                  <div className="action-buttons">
                    <button className="btn-contact" onClick={() => alert(`📧 Email: ${managerInfo.email}\n📱 Téléphone: ${managerInfo.phone}`)}>
                      📧 Contacter
                    </button>
                    <button className="btn-comment" onClick={() => alert("⭐ Note moyenne: 4.9/5\n📝 Commentaires: Excellent manager!")}>
                      💬 Évaluations
                    </button>
                  </div>
                  
                  {/* ========== 6 CARTES POUR LE VISITEUR (قراءة فقط) ========== */}
                  <div className="manager-cards-container">
                    
                    {/* المربع 1: إدارة الطاولات (قراءة فقط) */}
                    <div className="manager-card">
                      <div className="card-title"><span>🍽️</span> Gestion des tables</div>
                      <div className="table-list">
                        <h4 style={{ color: 'white', marginBottom: '10px' }}>Tables ({tables.length})</h4>
                        {tables.map(table => (
                          <div key={table.id} className="table-item">
                            <span style={{ color: 'white' }}>Table {table.number}</span>
                            <span style={{ color: '#22c55e', fontSize: '0.7rem' }}>QR Code disponible</span>
                          </div>
                        ))}
                        {tables.length === 0 && <p style={{ color: 'rgba(255,255,255,0.5)', textAlign: 'center' }}>Aucune table</p>}
                      </div>
                    </div>
                    
                    {/* المربع 2: إدارة المجموعات (قراءة فقط) */}
                    <div className="manager-card">
                      <div className="card-title"><span>👥</span> Gestion des groupes</div>
                      <div className="group-list">
                        <h4 style={{ color: 'white', marginBottom: '10px' }}>Groupes ({groups.length})</h4>
                        {groups.map(group => (
                          <div key={group.id} className="group-item">
                            <span style={{ color: 'white' }}>{group.name}</span>
                            {group.tableRange.start && (
                              <span style={{ fontSize: '0.7rem', color: '#22c55e' }}>
                                Tables: {group.tableRange.start} → {group.tableRange.end}
                              </span>
                            )}
                          </div>
                        ))}
                      </div>
                    </div>
                    
                    {/* المربع 3: ربط الموظفين (قراءة فقط) */}
                    <div className="manager-card">
                      <div className="card-title"><span>👨‍🍳</span> Employés</div>
                      <div className="employee-list">
                        <h4 style={{ color: 'white', marginBottom: '10px' }}>Employés ({employees.length})</h4>
                        {employees.map(emp => (
                          <div key={emp.id} className="employee-item">
                            <span style={{ color: 'white' }}>{emp.name}</span>
                            {emp.groupId && (
                              <span style={{ fontSize: '0.7rem', color: '#22c55e' }}>
                                → {groups.find(g => g.id === emp.groupId)?.name}
                              </span>
                            )}
                          </div>
                        ))}
                      </div>
                    </div>
                    
                    {/* المربع 4: المنيو (قراءة فقط) */}
                    <div className="manager-card">
                      <div className="card-title"><span>📝</span> Menu</div>
                      <div>
                        <h4 style={{ color: 'white', marginBottom: '10px', fontSize: '0.9rem' }}>Aperçu du menu</h4>
                        {menuCategories.slice(0, 2).map(cat => (
                          <div key={cat.id} style={{ marginBottom: '10px' }}>
                            <h5 style={{ color: cat.color, fontSize: '0.9rem' }}>{cat.icon} {cat.name}</h5>
                            <div style={{ fontSize: '0.7rem', color: 'rgba(255,255,255,0.6)' }}>{cat.products.length} produits</div>
                          </div>
                        ))}
                      </div>
                    </div>
                    
                    {/* المربع 5: كرت المطعم (قراءة فقط) */}
                    <div className="manager-card">
                      <div className="card-title"><span>🏪</span> Carte restaurant</div>
                      <div className="restaurant-card-preview">
                        <img src={restaurantData.logo} alt="logo" />
                        <h4 style={{ color: '#22c55e' }}>{restaurantData.name}</h4>
                        <p style={{ color: 'rgba(255,255,255,0.6)', fontSize: '0.8rem' }}>{restaurantData.location}</p>
                        <p style={{ color: 'rgba(255,255,255,0.5)', fontSize: '0.7rem' }}>⭐ {restaurantData.rating} • 👥 {restaurantData.employees} employés</p>
                      </div>
                    </div>
                    
                    {/* المربع 6: الفواتير (قراءة فقط) */}
                    <div className="manager-card">
                      <div className="card-title"><span>📊</span> Factures</div>
                      <button className="btn-primary" onClick={() => setShowInvoices(!showInvoices)} style={{ width: '100%' }}>
                        {showInvoices ? "🙈 Masquer" : "🔍 Afficher"}
                      </button>
                      {showInvoices && invoices.length > 0 && (
                        <div className="invoices-container">
                          <div className="invoice-tabs">
                            <button className={`invoice-tab ${invoiceViewType === 'tables' ? 'active' : ''}`} onClick={() => setInvoiceViewType('tables')}>🍽️ Tables</button>
                            <button className={`invoice-tab ${invoiceViewType === 'groups' ? 'active' : ''}`} onClick={() => setInvoiceViewType('groups')}>👥 Groupes</button>
                            <button className={`invoice-tab ${invoiceViewType === 'restaurant' ? 'active' : ''}`} onClick={() => setInvoiceViewType('restaurant')}>🏪 Restaurant</button>
                          </div>
                          {invoiceViewType === 'tables' && (
                            <>
                              <div className="invoice-stats"><h3>{getTotalRevenue()} DA</h3><p>Revenu total des tables</p></div>
                              <div className="table-list" style={{ maxHeight: '200px' }}>{invoices.slice(0, 5).map(inv => (<div key={inv.id} className="invoice-item"><span>Table {inv.tableNumber}</span><span style={{ color: '#22c55e' }}>{inv.total} DA</span></div>))}</div>
                            </>
                          )}
                          {invoiceViewType === 'groups' && (
                            <>
                              <div className="invoice-stats" style={{ background: 'linear-gradient(135deg, #3b82f6, #1d4ed8)' }}><h3>{groupInvoices.reduce((sum, g) => sum + g.total, 0)} DA</h3><p>Revenu total des groupes</p></div>
                              <div className="table-list" style={{ maxHeight: '200px' }}>{groupInvoices.map(group => (<div key={group.groupId} className="invoice-item group-invoice-item"><div><span style={{ fontWeight: 'bold' }}>{group.groupName}</span><div style={{ fontSize: '0.6rem' }}>{group.tableCount} tables</div></div><span>{group.total} DA</span></div>))}</div>
                            </>
                          )}
                          {invoiceViewType === 'restaurant' && restaurantInvoice && (
                            <div className="restaurant-invoice" style={{ padding: '15px', textAlign: 'center' }}><div style={{ fontSize: '2rem' }}>🏪</div><h3 style={{ color: '#22c55e', fontSize: '1.8rem' }}>{restaurantInvoice.total} DA</h3><p>Revenu total du restaurant</p></div>
                          )}
                        </div>
                      )}
                    </div>
                  </div>
                  
                  <div className="mt-10 py-10 border-t border-white/20 text-center">
                    <div className="flex flex-wrap justify-center">
                      <div className="w-full lg:w-9/12 px-4">
                        <p className="mb-4 text-lg leading-relaxed text-gray-200 italic">"{managerInfo.bio}"</p>
                        <div className="flex justify-center gap-2 mt-4 flex-wrap">
                          {managerInfo.skills.map((skill, i) => (<span key={i} className="skill-tag">{skill}</span>))}
                        </div>
                        <div className="flex justify-center gap-2 mt-4 flex-wrap">
                          {managerInfo.languages.map((lang, i) => (<span key={i} className="skill-tag">🌐 {lang}</span>))}
                        </div>
                      </div>
                    </div>
                  </div>
                  
                </div>
              </div>
            </div>
          </section>
        </main>
      </div>
      
      <SocialFooter socialLinks={socialLinks} />
      <Footer />
    </>
  );
}
